"use client"

import React, { useState, useEffect } from "react"
import { useTheme } from "next-themes"
import { X } from "lucide-react"

const QRIS_LIGHT = "data:image/jpeg;base64,"
const QRIS_DARK = "data:image/jpeg;base64,"

export function QrisSection() {
  const [showQris, setShowQris] = useState(false)
  const { resolvedTheme } = useTheme()
  const qrisSrc = resolvedTheme === "dark" ? QRIS_DARK : QRIS_LIGHT

  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === "Escape") setShowQris(false)
    }
    window.addEventListener("keydown", handleEsc)
    return () => window.removeEventListener("keydown", handleEsc)
  }, [])

  return (
    <>
      <button
        onClick={() => setShowQris(true)}
        className="fixed bottom-4 right-4 z-40 text-[10px] sm:text-xs font-mono text-muted-foreground/60 hover:text-primary transition-all hover:scale-105 active:scale-95 group flex items-center gap-1.5 bg-background/50 backdrop-blur-sm px-3 py-1.5 rounded-full border border-border/50 shadow-sm"
      >
        <span className="group-hover:animate-bounce">Ritual harian: Bayar pakai QRIS 😂</span>
      </button>

      {showQris && (
        <div
          className="fixed inset-0 bg-black/60 dark:bg-black/80 flex items-center justify-center z-50 p-4 backdrop-blur-[2px] animate-in fade-in duration-200"
          onClick={() => setShowQris(false)}
        >
          <div
            className="bg-white dark:bg-black rounded-2xl p-8 shadow-2xl relative max-w-sm w-full animate-in zoom-in-95 duration-200 border border-border/50"
            onClick={(e) => e.stopPropagation()}
          >
            <button
              onClick={() => setShowQris(false)}
              className="absolute top-4 right-4 text-slate-400 hover:text-slate-700 dark:hover:text-white transition-colors p-1"
            >
              <X className="w-5 h-5" />
            </button>

            <div className="flex flex-col items-center gap-6">
              <h3 className="font-mono text-lg font-bold text-slate-800 dark:text-slate-100">
                Scan QRIS untuk Bayar
              </h3>

              <div className="bg-white p-4 rounded-xl shadow-inner flex items-center justify-center w-full aspect-square max-w-[280px]">
                <img
                  src={qrisSrc}
                  alt="QRIS Code"
                  className="w-full h-full object-contain"
                />
              </div>

              <div className="text-center space-y-2">
                <p className="text-sm text-slate-500 dark:text-slate-400 font-medium">
                  Scan dengan aplikasi e-wallet atau mobile banking
                </p>
                <button
                  onClick={() => setShowQris(false)}
                  className="mt-4 w-full py-2.5 bg-slate-900 dark:bg-slate-100 text-white dark:text-black rounded-lg font-mono text-sm font-bold hover:opacity-90 transition-opacity"
                >
                  Tutup
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  )
}
